using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Categoria de inimigo (Enemy Creator — Etapa 1.1). Define o "tipo" do inimigo
/// para organização, gizmos/editor e futura lógica específica (ex: Torretas não
/// se movem, Armadilhas são estáticas por definição).
///
/// Em "Animals" quase todos os inimigos são máquinas humanas, drones, armadilhas
/// ou mecanismos industriais. "OrganicoCorrompido" cobre os raros inimigos
/// orgânicos corrompidos.
/// </summary>
public enum EnemyCategory
{
    Drone,
    Torreta,
    Armadilha,
    RoboTerrestre,
    MaquinaAquatica,
    HazardMovel,
    OrganicoCorrompido,
    MiniBoss
}

/// <summary>
/// Efeito de status que um item (ou outra fonte) pode causar num inimigo. Usado
/// por EnemyItemInteractionConfig para ligar itens específicos a efeitos, e para
/// listar imunidades (ex: um Mini-boss imune a "Sleep").
/// </summary>
public enum EnemyStatusEffect
{
    Sleep,
    Freeze,
    Trap,
    LoseTarget,
    Knockback,
    Stun,
    Other
}

/// <summary>
/// Estatísticas básicas de combate, movimento e reacção a dano de um inimigo
/// (Enemy Creator — Etapa 1.1). Configs de detecção, movimento, água, ataques e
/// drops são adicionadas a EnemyData nas etapas seguintes.
/// </summary>
[System.Serializable]
public class EnemyStats
{
    [Header("Vida")]
    [Tooltip("Vida máxima do inimigo.")]
    public int maxHealth = 10;

    [Header("Dano")]
    [Tooltip("Dano causado ao player apenas por tocar no inimigo (sem ser um ataque).")]
    public int contactDamage = 1;

    [Tooltip("Dano do ataque principal (ver lista de ataques — Etapa 2).")]
    public int primaryAttackDamage = 1;

    [Tooltip("Dano do ataque secundário, se existir (ver lista de ataques — Etapa 2). Deixa 0 se o inimigo só tiver um ataque.")]
    public int secondaryAttackDamage = 0;

    [Header("Movimento")]
    [Tooltip("Velocidade base de movimento (usada como referência por EnemyMovement — Etapa 1.5).")]
    public float moveSpeed = 2f;

    [Tooltip("Aceleração até à velocidade alvo.")]
    public float acceleration = 10f;

    [Header("Física")]
    [Tooltip("Peso do inimigo. Usado em empurrões, placas de peso (Etapa 6) e queda na água (Etapa 3).")]
    public float weight = 1f;

    [Tooltip("0 = sem resistência (knockback aplicado com força total). 1 = ignora knockback por completo.")]
    [Range(0f, 1f)]
    public float knockbackResistance = 0f;

    [Header("Combate")]
    [Tooltip("Tempo (segundos) em que o inimigo fica invencível depois de tomar um hit.")]
    public float invincibilityTimeAfterHit = 0.5f;

    [Header("Destruição / Invencibilidade")]
    [Tooltip("Se activo, ao chegar a 0 de vida o inimigo é destruído (Estado: Morto).")]
    public bool canBeDestroyed = true;

    [Tooltip("Se activo, ao chegar a 0 de vida o inimigo fica apenas Desactivado em vez de destruído (ex: máquinas que só desligam). Tem prioridade sobre 'canBeDestroyed' quando ambos estão activos.")]
    public bool canOnlyBeDeactivated = false;

    [Tooltip("Se activo, o inimigo nunca toma dano nem muda de estado por dano (ignora toda a lógica de vida/destruição).")]
    public bool isInvincible = false;

    [Header("Reacção ao Tomar Dano")]
    [Tooltip("Ao tomar dano, o inimigo recua (recebe knockback).")]
    public bool recoilOnHit = true;

    [Tooltip("Ao tomar dano, o inimigo fica parado (interrompe movimento/ataque por um curto período).")]
    public bool freezeOnHit = false;

    [Tooltip("Ao tomar dano, o inimigo pisca. Padrão: ligado — pode ser desligado por inimigo.")]
    public bool flashOnHit = true;

    [Header("Locomoção")]
    [Tooltip("Inimigo voador (ex: drones, aves). Usado por efeitos ambientais como a Resina Antiga: inimigos voadores não-imunes são puxados para baixo em vez de apenas imobilizados.")]
    public bool isFlying = false;
}

/// <summary>
/// Fraquezas e resistências de um inimigo (Enemy Creator — Etapa 1.1).
///
/// "weakAgainst" reutiliza o enum AnimalCategory (já usado para classificar as
/// formas do player no GDD — Rapido/Saltador/Escalador/Forte/Predador/Voador/
/// Aquatico/Furtivo/Resistente): ex. uma Torreta marcada como fraca contra
/// "Forte" pode ser destruída/empurrada por um player nessa forma; um Drone
/// fraco contra "Voador" ou "Predador" toma dano extra dessas formas.
/// </summary>
[System.Serializable]
public class EnemyWeaknessConfig
{
    [Header("Fraco Contra (Categorias do Player)")]
    [Tooltip("Categorias do AnimalCategory (formas do player) contra as quais este inimigo é fraco. Pode combinar mais que uma. Ex: Torreta = Forte; Drone = Voador | Predador.")]
    public AnimalCategory weakAgainst = AnimalCategory.None;

    [Tooltip("Multiplicador aplicado ao dano recebido quando o atacante tem uma categoria em 'weakAgainst' (GDD 12.1: \"dano não é fixo; depende da força do animal e da habilidade usada\"). Ex: 2 = dano dobrado. Consumido por EnemyHealth.TakeDamage(int, AnimalCategory, Vector2, float).")]
    [Min(1f)]
    public float weaknessDamageMultiplier = 2f;

    [Header("Controlo / Status")]
    public bool canBePushed = true;
    public bool canBePulled = false;
    public bool canBeFrozen = false;

    [Tooltip("Pode ser preso/imobilizado no chão (ex: por uma rede ou armadilha).")]
    public bool canBeGroundPinned = false;

    public bool canBePutToSleep = false;

    [Tooltip("Pode ser completamente ignorado por um player furtivo (não dispara a detecção deste inimigo). FONTE DE VERDADE da detecção de furtivos (Etapa 8.1): EnemyDetection deriva daqui por omissão (stealthDetection = Auto), com override manual opcional. Default ligado = furtividade funciona contra este inimigo.")]
    public bool canBeIgnoredByStealth = true;

    public bool canBeStunned = true;
    public bool canBeFlipped = false;

    [Header("Puzzle / Ambiente")]
    public bool canBeUsedAsPlatform = false;
    public bool canPressWeightPlate = false;
    public bool canActivateButton = false;
    public bool canBlockLaser = false;

    [Tooltip("Este inimigo pode ser parte da solução de um puzzle (ver EnemyPuzzleInteraction — Etapa 6).")]
    public bool canBeUsedToSolvePuzzle = false;

    [Tooltip("Os ataques deste inimigo destroem objectos destrutíveis (IProjectileDestructible) e activam switches (IProjectileActivatable) apanhados na área — ver EnemyPuzzleInteraction.ApplyAttackToObjects (Etapa 6.2). Projécteis têm as suas próprias flags em ProjectileData.")]
    public bool canDestroyObjectsOnAttack = false;

    [Header("Interacção Entre Inimigos")]
    [Tooltip("Os ataques/projécteis/explosões deste inimigo podem ferir outros inimigos.")]
    public bool canHurtOtherEnemies = false;

    [Tooltip("Este inimigo recebe dano de hazards do ambiente (espinhos, lava, etc).")]
    public bool canTakeDamageFromHazards = true;

    [Tooltip("Este inimigo recebe dano de projécteis disparados por outros inimigos.")]
    public bool canTakeDamageFromOtherEnemyProjectiles = false;
}

/// <summary>
/// Reacção de um inimigo a uma situação de água "errada" (Enemy Creator —
/// Etapa 3.1): não-nadador que cai na água, ou aquático que sai da água.
/// </summary>
public enum EnemyWaterReaction
{
    /// <summary>Não acontece nada (ex: robô à prova de água que apenas se afunda).</summary>
    Nenhuma,

    /// <summary>O inimigo passa a Desactivado (ex: máquina que entra em curto-circuito e desliga).</summary>
    Desactiva,

    /// <summary>O inimigo morre (passa por EnemyHealth.Kill — respeita "canOnlyBeDeactivated").</summary>
    Morre
}

/// <summary>
/// Configuração de água de um inimigo (Enemy Creator — Etapa 3.1), com os 3
/// conceitos do GDD:
///
/// - Terrestre (default): "canSwim" e "canDive" desligados. Se cair na água,
///   reage conforme "fallInWaterReaction" (morre/desactiva/nada acontece).
/// - Nada ("canSwim"): move-se na água mas fica na superfície — se submergir,
///   é empurrado de volta para cima ("floatToSurfaceSpeed").
/// - Mergulha ("canDive"): implica Nada (forçado em EnemyData.OnValidate).
///   Move-se livremente debaixo de água.
///
/// Consumida por EnemyWaterBehavior (componente no inimigo, que reutiliza o
/// WaterDetector partilhado com o player) e pelos ataques aquáticos (Etapa 3.2).
/// </summary>
[System.Serializable]
public class EnemyWaterConfig
{
    [Header("Conceitos")]
    [Tooltip("Nada: o inimigo consegue mover-se na água (na superfície). Desligado + 'canDive' desligado = Terrestre (default).")]
    public bool canSwim = false;

    [Tooltip("Mergulha: o inimigo move-se livremente debaixo de água. Implica 'Nada' (forçado automaticamente).")]
    public bool canDive = false;

    [Header("Não Sabe Nadar e Cai na Água")]
    [Tooltip("O que acontece a um inimigo SEM 'Nada' que cai na água (GDD: \"morre ao cair na água caso não saiba nadar?\").")]
    public EnemyWaterReaction fallInWaterReaction = EnemyWaterReaction.Morre;

    [Tooltip("Tempo (segundos) dentro de água antes da reacção acima ser aplicada (0 = imediato).")]
    [Min(0f)]
    public float fallInWaterDelay = 0.5f;

    [Header("Aquático Fora de Água")]
    [Tooltip("Este inimigo morre/desactiva se ficar fora de água (GDD: \"morre fora da água?\"). Só faz sentido com 'Nada' ligado.")]
    public bool diesOutOfWater = false;

    [Tooltip("Reacção aplicada quando 'diesOutOfWater' está ligado e o tempo fora de água esgota.")]
    public EnemyWaterReaction outOfWaterReaction = EnemyWaterReaction.Morre;

    [Tooltip("Tempo (segundos) que o inimigo aguenta fora de água antes da reacção.")]
    [Min(0f)]
    public float outOfWaterDelay = 3f;

    [Header("Movimento na Água")]
    [Tooltip("Velocidade máxima dentro de água (limita a velocidade do Rigidbody2D enquanto em água). 0 = sem limite (usa as velocidades normais de EnemyMovement).")]
    [Min(0f)]
    public float swimSpeed = 0f;

    [Tooltip("Velocidade vertical com que um nadador SEM 'Mergulha' é empurrado de volta para a superfície quando submerge.")]
    [Min(0f)]
    public float floatToSurfaceSpeed = 2f;

    [Tooltip("O inimigo aquático pode sair da água (ex: saltar para apanhar o player)? Desligado = fica travado à superfície. Só relevante com 'Nada' ligado (Etapa 3.2).")]
    public bool canLeaveWater = false;

    /// <summary>True se o inimigo é Terrestre (não nada nem mergulha) — o conceito default.</summary>
    public bool IsTerrestrial => !canSwim && !canDive;
}

/// <summary>
/// Drops de um inimigo (Enemy Creator — Etapa 4.3). Consumida pelo componente
/// EnemyDropTable, que escuta EnemyController.OnStateChanged e entrega os
/// drops via PlayerProgress quando o inimigo morre (e, opcionalmente, quando
/// é desactivado).
/// </summary>
[System.Serializable]
public class EnemyDropConfig
{
    [Header("Sementes")]
    [Tooltip("Quantidade mínima de Sementes dropadas (0-0 = não dropa Sementes).")]
    [Min(0)] public int seedsMin = 0;

    [Tooltip("Quantidade máxima de Sementes dropadas.")]
    [Min(0)] public int seedsMax = 0;

    [Header("Broto de Vida")]
    [Tooltip("Probabilidade (0..1) de dropar 1 Broto de Vida.")]
    [Range(0f, 1f)] public float lifeSproutChance = 0f;

    [Header("Item Especial")]
    [Tooltip("Item especial dropado por este inimigo (vazio = nenhum). Se for um item de missão, marca 'isMissionItem' no próprio ItemData.")]
    public ItemData specialItem;

    [Min(1)] public int specialItemQuantity = 1;

    [Tooltip("O drop especial acontece só UMA vez e fica salvo como recolhido (PlayerProgress.collectedSpecialItemIds) — não repete após reentrar na área. Também respeita 'dropsOnlyOnce' do próprio ItemData.")]
    public bool specialDropOnlyOnce = true;

    [Header("Condição do Drop Especial (GameVariables)")]
    [Tooltip("Nome de uma variável global bool que tem de ter o valor esperado para o item especial dropar (ex: variável de missão activa — Etapa 5.1). Vazio = sem condição.")]
    public string requiredBoolVariable = "";

    public bool requiredBoolValue = true;

    [Header("Quando Dropa")]
    [Tooltip("Também dropa quando o inimigo é Desactivado (e não só quando Morre).")]
    public bool dropOnDeactivated = false;
}

/// <summary>
/// Liga um ItemData a um efeito de status (ver
/// EnemyItemInteractionConfig.otherItemEffects).
/// </summary>
[System.Serializable]
public class ItemEffectEntry
{
    public ItemData item;
    public EnemyStatusEffect effect;
}

/// <summary>
/// Interacção do inimigo com itens do jogo (Enemy Creator — Etapa 1.1). Os
/// campos específicos cobrem os itens já previstos no GDD (Flor do Silêncio,
/// Resina Antiga, Pó Dourado, Cristal de Gelo, Bolha de Coral). "otherItemEffects"
/// e "immuneItems"/"immuneEffects" deixam o sistema preparado para novos itens
/// globais/regionais e para imunidades de Mini-boss (ex: imune a sono) sem
/// precisar de novos campos.
/// </summary>
[System.Serializable]
public class EnemyItemInteractionConfig
{
    [Header("Itens do GDD")]
    [Tooltip("Flor do Silêncio: o inimigo pode adormecer com este item.")]
    public bool canSleepFromSilenceFlower = false;

    [Tooltip("Resina Antiga: o inimigo pode ficar preso/imobilizado com este item.")]
    public bool canBeTrappedByAncientResin = false;

    [Tooltip("Pó Dourado: o inimigo perde o alvo (deixa de perseguir o player) ao ser afectado por este item.")]
    public bool losesTargetFromGoldenDust = false;

    [Tooltip("Cristal de Gelo: o inimigo pode ser congelado por este item.")]
    public bool canBeFrozenByIceCrystal = false;

    [Tooltip("OBSOLETO (Tarefa \"Itens Consumíveis\"): Bolha de Coral passou a ser um buff exclusivo do player (imunidade a correntes de água) e já não afecta inimigos. Este campo é ignorado — mantido apenas para não invalidar assets antigos.")]
    public bool affectedByCoralBubble = false;

    [Header("Geral")]
    [Tooltip("O inimigo é afectado por knockback causado por itens (ex: empurrões/explosões de itens do player).")]
    public bool affectedByKnockbackItems = true;

    [Header("Outros Itens Globais/Regionais")]
    [Tooltip("Liga quaisquer outros ItemData (globais/regionais, actuais ou futuros) a um efeito de status neste inimigo.")]
    public List<ItemEffectEntry> otherItemEffects = new List<ItemEffectEntry>();

    [Header("Imunidades")]
    [Tooltip("Efeitos de status aos quais este inimigo é totalmente imune (ex: Mini-boss imune a Sleep).")]
    public List<EnemyStatusEffect> immuneEffects = new List<EnemyStatusEffect>();

    [Tooltip("Itens específicos aos quais este inimigo é totalmente imune, independentemente do efeito configurado para esse item.")]
    public List<ItemData> immuneItems = new List<ItemData>();
}

/// <summary>
/// Define os dados de um inimigo (Enemy Creator — Etapa 1.1): identidade, visual,
/// prefab, categoria, estatísticas, fraquezas/resistências e interacção com
/// itens. Um EnemyController referencia um EnemyData e pode ser colocado várias
/// vezes na cena, todos partilhando a mesma configuração base.
///
/// As próximas etapas adicionam a este ScriptableObject: detecção (1.4),
/// movimento/patrulha (1.5), água (Etapa 3), ataques/projécteis (Etapa 2) e
/// drops (Etapa 4).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Enemy/Enemy Data", fileName = "NewEnemyData")]
public class EnemyData : ScriptableObject
{
    [Header("Identidade")]
    [Tooltip("Identificador único deste inimigo (usado por condições, registos de derrota, drops, etc).")]
    public string enemyId;

    public string displayName;

    [Tooltip("Categoria do inimigo. Quase todos são robóticos/mecânicos (Drone, Torreta, Armadilha, Robô Terrestre, Máquina Aquática, Hazard Móvel, Mini-boss). 'OrganicoCorrompido' é só para os raros inimigos orgânicos corrompidos.")]
    public EnemyCategory category = EnemyCategory.RoboTerrestre;

    [Header("Visual")]
    [Tooltip("Sprite estático (opcional — usar se o inimigo não tiver Animator).")]
    public Sprite sprite;

    [Tooltip("Animator Controller do inimigo (opcional — usar se o inimigo tiver animações).")]
    public RuntimeAnimatorController animatorController;

    [Header("Prefab")]
    [Tooltip("Prefab base deste inimigo, com EnemyController e os componentes necessários já configurados.")]
    public GameObject prefab;

    [Header("Estatísticas")]
    public EnemyStats stats = new EnemyStats();

    [Header("Fraquezas e Resistências")]
    public EnemyWeaknessConfig weaknesses = new EnemyWeaknessConfig();

    [Header("Água (Etapa 3)")]
    public EnemyWaterConfig water = new EnemyWaterConfig();

    [Header("Drops (Etapa 4.3)")]
    public EnemyDropConfig drops = new EnemyDropConfig();

    [Header("Interacção com Itens")]
    public EnemyItemInteractionConfig itemInteractions = new EnemyItemInteractionConfig();

    private void OnValidate()
    {
        // Mergulha implica Nada (Etapa 3.1).
        if (water != null && water.canDive)
            water.canSwim = true;
    }
}
